interface.definition:
a!localVariables(
  local!tasksPagingInfo: #"SYSTEM_SYSRULES_pagingInfo"(
    startIndex: 1,
    batchSize: 3,
    sort: #"SYSTEM_SYSRULES_sortInfo"(
      field: "c7",
      ascending: false
    )
  ),
  local!tasks: a!refreshVariable(
    value: a!queryProcessAnalytics(
      report: #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1061067",
      query: #"SYSTEM_SYSRULES_query"(
        logicalExpression: #"SYSTEM_SYSRULES_queryLogicalExpression"(
          operator: "AND",
          ignoreFiltersWithEmptyValues: true,
          filters: {
            #"SYSTEM_SYSRULES_queryFilter"(
              field: "c10",
              operator: "=",
              value: loggedInUser()
            ),
            #"SYSTEM_SYSRULES_queryFilter"(
              field: "c8",
              operator: "in",
              value: {
                #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1638701",
                #"_a-0000ee50-153e-8000-88de-179188179188_18081"
              }
            )
          }
        ),
        pagingInfo: local!tasksPagingInfo
      )
    ),
    refreshInterval: 1,
    refreshAlways: true
  ),

  local!inmate: #"_a-0000ed87-2144-8000-9bee-011c48011c48_1418098"(userName: loggedInUser()),

  local!requests: #"SYSTEM_SYSRULES_queryRecordType_v2"(
    recordType: #"urn:appian:record-type:v1:869b0f23-8e42-4780-8dfc-89deb24c798d",
    filters: #"SYSTEM_SYSRULES_queryLogicalExpression"(
      operator: "AND",
      filters: {
        #"SYSTEM_SYSRULES_queryFilter"(
          field: #"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/a2e6a1a3-9952-4aee-a7d5-c5077d3fb9be",
          operator: "=",
          value: local!inmate[#"urn:appian:record-field:v1:b9f2b8a1-aa3c-420e-9856-a362e5c58683/d70d7a0c-0ee6-4949-84d6-2c58d8caffcc"]
        ),
        #"SYSTEM_SYSRULES_queryFilter"(
          field: #"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/7ac9c394-ee75-466f-9790-274b821dd0af",
          operator: "<>",
          value: #"_a-0000ed87-2144-8000-9bee-011c48011c48_1411847"
        ),
      }
    ),
    pagingInfo: #"SYSTEM_SYSRULES_pagingInfo"(1, 5000, #"SYSTEM_SYSRULES_sortInfo"(#"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/ab4316cc-3bee-4bb9-b663-14ee81dc52b3"))
  ).data,

  #"SYSTEM_SYSRULES_headerContentLayout"(
    header: #"SYSTEM_SYSRULES_billboardLayout_v1"(
      backgroundColor: "#f0f0f0",

      height: "EXTRA_SHORT",
      marginAbove: "NONE",
      marginBelow: "NONE",
      overlay: #"SYSTEM_SYSRULES_fullOverlay"(
        contents: {
          #"SYSTEM_SYSRULES_richTextDisplayField"(
            value: #"SYSTEM_SYSRULES_richTextItem_v1"(
              text: #"urn:appian:translation-string:v1:eee4823d-3383-4617-8cba-5ce661291345" & " " & user(loggedInUser(), "firstName"),
              size: "LARGE"
            )
          )
        },
        style: "NONE"
      )
    ),
    isHeaderFixed: true,
    contents: {
      #"SYSTEM_SYSRULES_sectionLayout_v1"(
        contents: {
          #"SYSTEM_SYSRULES_columnsLayout"(
            columns: {
              #"SYSTEM_SYSRULES_columnLayout"(
                contents: {
                  #"_a-0000ed87-2144-8000-9bee-011c48011c48_1418867"(
                    contents: #"SYSTEM_SYSRULES_sectionLayout_v1"(
                      label: "Aufgaben",
                      labelIcon: "tasks-alt",
                      labelColor: "STANDARD",
                      contents: {
                        if(
                          a!isNullOrEmpty(local!tasks.data), 
                          #"SYSTEM_SYSRULES_richTextDisplayField"(
                            value: #"SYSTEM_SYSRULES_richTextItem_v1"(
                              text: "Aktuell gibt es keine Aufgaben",
                              style: "EMPHASIS"                            
                            ),
                            align: "CENTER",
                            marginAbove: "MORE"
                          ),
                          /*Aufgabenliste*/
                          #"SYSTEM_SYSRULES_forEach"(
                            items: {
                              local!tasks.data
                            },
                            expression: #"SYSTEM_SYSRULES_cardLayout"(
                              contents: {
                                #"SYSTEM_SYSRULES_sideBySideLayout"(
                                  items: {
                                    #"SYSTEM_SYSRULES_sideBySideItem"(
                                      item: #"SYSTEM_SYSRULES_richTextDisplayField"(
                                        labelPosition: "COLLAPSED",
                                        value: {
                                          #"SYSTEM_SYSRULES_richTextItem_v1"(
                                            text: fv!item.c0,
                                            size: "MEDIUM_PLUS"
                                          ),
                                          char(10),
                                          #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1609689"(dateTime: fv!item.c2),
                                          " - ",
                                          #"SYSTEM_SYSRULES_richTextItem_v1"(
                                            text: #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1609689"(dateTime: fv!item.c7),
                                            style: "STRONG"
                                          )
                                        }
                                      )
                                    )
                                    /*a!sideBySideItem(*/
                                    /*item: a!richTextDisplayField(*/
                                    /*labelPosition: "COLLAPSED",*/
                                    /*value: a!richTextIcon(*/
                                    /*icon: if(*/
                                    /*now() > todatetime(fv!item.c2),*/
                                    /*"exclamation-circle",*/
                                    /*"clock"*/
                                    /*),*/
                                    /*color: if(*/
                                    /*now() > todatetime(fv!item.c2),*/
                                    /*"NEGATIVE",*/
                                    /*"STANDARD"*/
                                    /*),*/
                                    /*size: "LARGE"*/
                                    /*)*/
                                    /*),*/
                                    /*width: "MINIMIZE"*/
                                    /*)*/
                                  },
                                  alignVertical: "MIDDLE"
                                )
                              },
                              link: #"SYSTEM_SYSRULES_processTaskLink"(
                                task: fv!item.dp0,
                                showWhen: a!isNotNullOrEmpty(fv!item.dp0)
                              ),
                              style: "INFO",
                              shape: "ROUNDED",
                              marginBelow: "STANDARD",
                              showBorder: false
                            )
                          )
                        ),
                        #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1616691"(
                          pagingInfo: local!tasksPagingInfo,
                          saveInto: local!tasksPagingInfo,
                          totalCount: local!tasks.totalCount,
                          align: "CENTER"
                        )
                      }
                    )
                  )
                },
                width: "3X"
              ),
              #"SYSTEM_SYSRULES_columnLayout"(
                contents: {
                  /*Hier Meldungen*/
                  #"_a-0000ee46-8277-8000-88d4-179188179188_12345"()
                },
                width: "3X"
              ),
              #"SYSTEM_SYSRULES_columnLayout"(
                contents: {
                  #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1616294"(
                    label: #"urn:appian:translation-string:v1:9ccbd1ae-02d1-409e-a283-9e0c76b8874a",
                    icon: "file-export",
                    size: "MEDIUM"
                  ),
                  #"SYSTEM_SYSRULES_recordActionField_v1"(
                    actions: {
                      #"SYSTEM_SYSRULES_recordActionItem"(
                        action: #"urn:appian:record-action:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/fec536c2-4bc8-47c1-9082-33bfb3fc4479"
                      ),
                      #"SYSTEM_SYSRULES_recordActionItem"(
                        action: #"urn:appian:record-action:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/f0c293b7-38ab-4f00-8c89-6609e33ba6cb"
                      ),
                      #"SYSTEM_SYSRULES_recordActionItem"(
                        action: #"urn:appian:record-action:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/51b56dfa-5e65-4172-ab81-b4e32c028368"
                      )
                    },
                    style: "SIDEBAR",
                    align: "CENTER"
                  )
                },
                width: "1X"
              )          
            },
            alignVertical: "TOP"
          ),

          #"SYSTEM_SYSRULES_columnsLayout"(
            columns: {
              #"SYSTEM_SYSRULES_columnLayout"(
                width: "6X",
                contents: {
                  #"_a-0000ed87-2144-8000-9bee-011c48011c48_1418867"(
                    contents: { 

                      #"SYSTEM_SYSRULES_sectionLayout_v1"(
                        label: "Offene Anträge",
                        labelIcon: "files-solid",
                        labelColor: "STANDARD",
                        contents: {

                          #"SYSTEM_SYSRULES_gridField_v3"(
                            label: #"urn:appian:translation-string:v1:4017e339-6f79-454b-a5b2-6da958d6c059"& " " & #"urn:appian:translation-string:v1:84159852-a462-4f83-aa82-f26e03d5c579",
                            labelPosition: "COLLAPSED",
                            accessibilityText: #"urn:appian:translation-string:v1:4017e339-6f79-454b-a5b2-6da958d6c059" & " " & #"urn:appian:translation-string:v1:84159852-a462-4f83-aa82-f26e03d5c579",
                            data: local!requests,
                            initialSorts: #"SYSTEM_SYSRULES_sortInfo"(#"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/f3ba344c-c6d8-48a9-b57e-2ac2380a8f74"),
                            pageSize: 20,
                            shadeAlternateRows: true,
                            columns: {
                              #"SYSTEM_SYSRULES_gridColumn"(
                                accessibilityText: #"urn:appian:translation-string:v1:9b5a63b2-4919-4549-a971-449c3aa98693" & " " & #"urn:appian:translation-string:v1:f2d65b84-c85d-42bc-ad74-4ce23812eb15",
                                width: "ICON",
                                value: #"SYSTEM_SYSRULES_richTextDisplayField"(
                                  value: #"SYSTEM_SYSRULES_richTextIcon"(
                                    size: "MEDIUM",
                                    icon: #"_a-0000ed87-2144-8000-9bee-011c48011c48_1418353"(requestStatus: fv!row[#"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/7ac9c394-ee75-466f-9790-274b821dd0af"]).icon,
                                    color: #"_a-0000ed87-2144-8000-9bee-011c48011c48_1418353"(requestStatus: fv!row[#"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/7ac9c394-ee75-466f-9790-274b821dd0af"]).color
                                  )
                                )
                              ),
                              #"SYSTEM_SYSRULES_gridColumn"(
                                label: #"urn:appian:translation-string:v1:4017e339-6f79-454b-a5b2-6da958d6c059",
                                width: "MEDIUM",
                                accessibilityText: #"urn:appian:translation-string:v1:4017e339-6f79-454b-a5b2-6da958d6c059" & " " & #"urn:appian:translation-string:v1:17ad354e-3578-46b4-a350-d0487645f33a",
                                sortField: #"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/8f6e62d6-f646-45a8-a038-e356580cbf87",
                                value: #"SYSTEM_SYSRULES_linkField"(
                                  accessibilityText: "Hyperlink to Request Summary Dashboard",
                                  links: #"SYSTEM_SYSRULES_recordLink"(
                                    label: #"_a-0000ed87-2144-8000-9bee-011c48011c48_1418207"(requestType: fv!row[#"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/8f6e62d6-f646-45a8-a038-e356580cbf87"]).translation,
                                    recordType: #"urn:appian:record-type:v1:869b0f23-8e42-4780-8dfc-89deb24c798d",
                                    identifier: fv!row[#"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/ab4316cc-3bee-4bb9-b663-14ee81dc52b3"],
                                    dashboard: "summary",
                                    openLinkIn: "NEW_TAB"
                                  )
                                )
                              ),
                              #"SYSTEM_SYSRULES_gridColumn"(
                                label: #"urn:appian:translation-string:v1:9818ce68-55e7-49d6-9d1c-b92fe4c4e1c0",
                                accessibilityText: "Betreff" & " " & #"urn:appian:translation-string:v1:17ad354e-3578-46b4-a350-d0487645f33a",
                                value: if(
                                        fv!row[#"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/8f6e62d6-f646-45a8-a038-e356580cbf87"] = #"_a-0000ed87-2144-8000-9bee-011c48011c48_1417768",
                                        #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1543632"(month: fv!row[#"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/c705d2d0-bbc1-404a-bbc5-93cffc1a8c52"]) & " " & fv!row[#"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/13ac8f18-8fd8-4341-8f42-86db1aaa8588"],
                                        fv!row[#"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/95432e14-73d0-40f5-aef3-cfa048d229b2"],
                                      )
                              ),
                              #"SYSTEM_SYSRULES_gridColumn"(
                                label: #"urn:appian:translation-string:v1:e11de595-298f-4b0c-808f-40e396341e1b",
                                accessibilityText: #"urn:appian:translation-string:v1:e11de595-298f-4b0c-808f-40e396341e1b" & " " & #"urn:appian:translation-string:v1:17ad354e-3578-46b4-a350-d0487645f33a",
                                sortField: #"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/a2219542-a8b5-464d-9306-5654dce49a83",
                                value: text(fv!row[#"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/a2219542-a8b5-464d-9306-5654dce49a83"], "dd.MM.yyyy"),
                              ),
                              #"SYSTEM_SYSRULES_gridColumn"(
                                label: #"urn:appian:translation-string:v1:9b5a63b2-4919-4549-a971-449c3aa98693",
                                accessibilityText: #"urn:appian:translation-string:v1:9b5a63b2-4919-4549-a971-449c3aa98693" & " " & #"urn:appian:translation-string:v1:17ad354e-3578-46b4-a350-d0487645f33a",
                                sortField: #"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/7ac9c394-ee75-466f-9790-274b821dd0af",
                                value: if(
                                  /*Only show In Progress or Completed to the inmate. For any other status, they have to see In Progress*/
                                  or(
                                    fv!row[#"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/7ac9c394-ee75-466f-9790-274b821dd0af"] = #"_a-0000ed87-2144-8000-9bee-011c48011c48_1411841",
                                    fv!row[#"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/7ac9c394-ee75-466f-9790-274b821dd0af"] = #"_a-0000ed87-2144-8000-9bee-011c48011c48_1411847"
                                  ),
                                  #"_a-0000ed87-2144-8000-9bee-011c48011c48_1418353"(requestStatus: fv!row[#"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/7ac9c394-ee75-466f-9790-274b821dd0af"]).translation,
                                  #"_a-0000ed87-2144-8000-9bee-011c48011c48_1418353"(requestStatus: #"_a-0000ed87-2144-8000-9bee-011c48011c48_1411841").translation
                                )
                              ),
                              #"SYSTEM_SYSRULES_gridColumn"(
                                label: #"urn:appian:translation-string:v1:e64fd894-261d-4730-9337-e4d1c9e50e05",
                                accessibilityText: #"urn:appian:translation-string:v1:e64fd894-261d-4730-9337-e4d1c9e50e05" & " " & #"urn:appian:translation-string:v1:17ad354e-3578-46b4-a350-d0487645f33a",
                                sortField: #"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/d70e3d78-9e76-4cdf-87df-70266c671007",
                                value: #"_a-0000ed87-2144-8000-9bee-011c48011c48_1418347"(requestDecision: fv!row[#"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/d70e3d78-9e76-4cdf-87df-70266c671007"]).translation
                              ),
                              #"SYSTEM_SYSRULES_gridColumn"(
                                label: #"urn:appian:translation-string:v1:61f6d12b-7a04-4f1d-8935-b48eedcc2b52",
                                accessibilityText: #"urn:appian:translation-string:v1:61f6d12b-7a04-4f1d-8935-b48eedcc2b52" & " " & #"urn:appian:translation-string:v1:17ad354e-3578-46b4-a350-d0487645f33a",
                                sortField: #"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/e135c951-3466-4d62-a892-71509c879628/8f04250a-23ba-4438-9ca4-5e7ab5ce495a",
                                value: #"_a-0000ee09-79c9-8000-9bf0-011c48011c48_1478522"(questionStatus: fv!row[#"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/e135c951-3466-4d62-a892-71509c879628/8f04250a-23ba-4438-9ca4-5e7ab5ce495a"]).translation
                              )
                            }
                          )
                        }
                      )
                    }
                  )
                }
              ),
              #"SYSTEM_SYSRULES_columnLayout"(
                width: "1X",
              )
            }
          )
        }
      ),
      #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1531272"(showContact: false)
    },
    backgroundColor: "TRANSPARENT",
    contentsPadding: "LESS"
  )
)
